import type { DefaultSession } from 'next-auth';

// Aumenta os tipos do NextAuth para incluir id e role do usuário na sessão/JWT.
declare module 'next-auth' {
  interface Session {
    user: {
      id: string;
      role: string;
    } & DefaultSession['user'];
  }

  interface User {
    role: string;
  }
}

declare module 'next-auth/jwt' {
  interface JWT {
    id: string;
    role: string;
  }
}
